import{_ as l,M as i,p as o,q as n,R as e,t,N as r,a1 as s}from"./framework-822ca1a4.js";const h={},c=e("h1",{id:"每周一词-potential",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#每周一词-potential","aria-hidden":"true"},"#"),t(" 每周一词-Potential")],-1),d=e("p",null,"2023 年 5 月 2 日 17:35:00",-1),p={href:"https://www.bbc.co.uk/learningenglish/chinese/features/english-in-a-minute/ep-230428",target:"_blank",rel:"noopener noreferrer"},u=s('<h2 id="简介" tabindex="-1"><a class="header-anchor" href="#简介" aria-hidden="true">#</a> 简介</h2><p>“Potential”既可以作名词，也可以作形容词。名词“potential”可以用来指人的“潜力，潜能”和事物发生的“可能性”。形容词可以指“潜在的，可能的”。</p><h2 id="用法总结" tabindex="-1"><a class="header-anchor" href="#用法总结" aria-hidden="true">#</a> 用法总结</h2><ol><li>名词“potential”可以表示“潜力，潜能”。</li></ol><ul><li>He only started the job this year, but he has a lot of potential.</li><li>This recipe has potential. It could be perfect if you make some small changes.</li></ul><ol start="2"><li>名词“potential”还可以表示“可能性，潜在性”。</li></ol><ul><li>These chemicals have the potential to cause lung damage.</li><li>There is potential for further housing developments in the area.</li></ul><ol start="3"><li>形容词“potential”的意思是“潜在的，可能的”。</li></ol><ul><li>Potential customers are waiting for the price to fall before buying it.</li><li>Be careful near the ocean! There&#39;s potential danger.</li></ul>',9);function _(f,m){const a=i("ExternalLinkIcon");return o(),n("div",null,[c,d,e("p",null,[e("a",p,[t("BBC"),r(a)])]),u])}const g=l(h,[["render",_],["__file","word-potential.html.vue"]]);export{g as default};
